          "Debug assign intrinsic should have had uses removed.");
-  AssignIntrinsicFn->eraseFromParent();
+  if (AssignIntrinsicFn->hasZeroLiveUses()) {
+    AssignIntrinsicFn->eraseFromParent();
+  }
