          "Debug label intrinsic should have had uses removed.");
-  LabelntrinsicFn->eraseFromParent();
+  if (LabelntrinsicFn->hasZeroLiveUses()) {
+    LabelntrinsicFn->eraseFromParent();
+  }
 }

